def test_go_contracts():
    agent_tests = sorted((APP / "internal/delivery").glob("*_test.go"))
    assert agent_tests == [], f"agent added delivery test files: {agent_tests}"
    for relative, content in FILES.items():
        path = APP / relative
        path.parent.mkdir(parents=True, exist_ok=True)
        path.write_text(content, encoding="utf-8")
    result = subprocess.run(
        ["/usr/local/go/bin/go", "test", "-race", "./internal/dispatch", "./internal/delivery", "./internal/idempotency", "-count=1"],
        cwd=APP,
        capture_output=True,
        text=True,
        timeout=120,
    )
    assert result.returncode == 0, result.stdout + result.stderr
